entry.content:
#poster {
	width: 100%;
	height: 445px;
	position: relative;
}
.posterC {
	display: inline-block;
	width: 100%;
	height: 500px;
	background: url(../img/20160713154957678313.jpg) no-repeat center center;
}
.posterL {
	position: absolute;
	left: 0;
	top: 50%;
	margin-top: -28px;
	width: 60px;
	height: 58px;
	background: url(../img/bg.png) no-repeat 15px -303px;
}
.posterL:hover {
	margin-top: -60px;
	height: 160px;
	background: url(../img/bg.png) no-repeat 0 -452px;
}
.posterR {
	position: absolute;
	right: 0;
	top: 50%;
	margin-top: -28px;
	width: 60px;
	height: 58px;
	background: url(../img/bg.png) no-repeat -205px -303px;
}
.posterR:hover {
	margin-top: -60px;
	height: 160px;
	background: url(../img/bg.png) no-repeat -190px -452px;
}
.musicList {
	margin-top: 40px;
	color: #fff;
}
.musicListCon {
	width: 1000px;
	margin: 0 auto;
}

body,
form,
p,
dl,
dd {
	margin: 0;
}
h1,h2,h3 {
	font-weight: normal;
	margin: 0;
}
ul {
	margin: 0;
	padding: 0;
	list-style: none;
}
a {
	text-decoration: none;
}
img {
	border: 0;
	vertical-align: top;
}
input {
	padding: 0;
	border: 0;
	outline: none;
}
body a:hover {
	color: #009af3;
}
body {
	min-width: 1000px;
}
.clearFix {
	zoom: 1;
}
.clearFix:after {
	content: "";
	display: block;
	clear: both;
}
/* 头部样式 */
#head {
	background: #fff;
}
.headContent {
	width: 1000px;
	height: 37px;
	padding: 20px 0 21px 0;
	margin: 0 auto;
}
.logo {
	float: left;
	height: 37px;
}
.logo a {
	display: inline-block;
}
.logo img {
	width: 153px;
	height: 37px;
}
.search {
	float: left;
	height: 34px;
	margin-left:40px;
	border: 1px solid #ccc;
}
.search form {
	float: left;
}
.input {
	font: 13px/24px "微软雅黑";
	margin-left: 14px;
	padding: 5px 0;
	width: 249px;
	color: #666;
}
.submit {
	float: right;
	width: 14px;
	height: 14px;
	padding: 9px 11px 11px 10px;
	background: url(../img/bg.png) no-repeat 10px 9px;
}
.submit:hover {
	background: url(../img/bg.png) no-repeat -21px 9px;
}
.headNav {
	float: right;
	width: 388px;
	font: 13px "微软雅黑";
}
.headNavL {
	float: left;
	margin: 10px 0 8px 1px;
	line-height: 19px;
	border-right: 1px solid #e6e6e6;
}
.headNavL a {
	float: left;
	margin-right: 30px;
	color: #777;
}
.headNavR {
	float: right;
	padding: 5px 0 2px 0;
	line-height: 28px;
}
.headNavR a {
	display: inline-block;
	height: 28px;
	width: 48px;
	text-align: center;
}
.login {
	border: 1px solid #169af3;
	background: #169af3;
	color: #fff;
	margin-right: 6px;
	border-radius: 3px 0;
}
.login:hover {
	border-color: #158fe1;
	background: #158fe1;
	color: #fff;
}
.register {
	border: 1px solid #dbdbdb;
	background: #fff;
	color: #777;
	border-radius: 3px 0;
}
.register:hover {
	border-color: #009af3;
}

/*导航样式*/

#nav {
	height: 55px;
	background-color: #2c323b;
}
.navContent {
	width: 1000px;
	margin: 0 auto;
}
.navContentL {
	float: left;
	font: 16px/55px "微软雅黑";
}
.navMore,
.navContentL a {
	float: left;
	padding: 0 30px;
	color: #ddd;
}
.navMore:hover h2 a,
.navContentL .navActive,
.navContentL a:hover {
	color: #fff;
	background: #0c8ed9;
}
.navMore {
	width: 113px;
	padding: 0;
	position: relative;
	background: url(../img/bg.png) no-repeat 77px -16px;
}
.navMore:hover {
	background: #0c8ed9 url(../img/bg.png) no-repeat 77px -53px;
}
.navMore h2 {
	padding: 0 30px;
	margin-left: 5px;
	font: 16px/55px "微软雅黑";
}
.navMore a {
	color: #ddd;
}
.hiddenNav {
	position: absolute;
	top: 55px;
	left: 0;
	width: 100%;
	z-index: 2;
	background-color: #252b34;
}
.navMore:hover .hiddenNav li {
	height: 36px;
}
.hiddenNav li {
	width: 100%;
	height: 0;
	font: 15px/36px "微软雅黑";
	text-align: center;
	overflow: hidden;
}
.hiddenNav a {
	display: block;
	color: #bbb;
}
.hiddenNav a:hover {
	color: #fff;
	background-color: #2d343d;
	line-height: 34px;
	border-top: 1px solid #383d44;
}
.navContentR {
	float: right;
	font: 13px/14px "微软雅黑";
	margin-top: 21px;
}
.navContentR a {
	display: inline-block;
	margin-left: 30px;
	padding-left: 20px;
	color: #bbb;
	background-image: url(../img/bg.png);
	background-repeat: no-repeat;
}
.navContentR a:hover {
	color: #14a9ff;
}
.show {
	background-position: 0 -110px;
}
.live {
	background-position: 0 -142px;
}
.musicAuthor {
	background-position: 0 -172px;
}
.game {
	background-position: 0 -202px;
}
.shop {
	background-position: 0 -228px;
}
.show:hover {
	background-position: -94px -110px;
}
.live:hover {
	background-position: -94px -142px;
}
.musicAuthor:hover {
	background-position: -94px -173px;
}
.game:hover {
	background-position: -94px -203px;
}
.shop:hover {
	background-position: -94px -229px;
}

/* 页脚 */

.footer {
	background: #2c323b;
	padding-bottom: 10px;
}
.footerNav {
	font: 12px/1.5 "微软雅黑";
	color: #b1b3b9;
	padding: 15px 0;
	text-align: center;
	border-bottom: 1px solid #3d424a;
}
.footerNav a {
	padding: 0 10px;
	color: #b1b3b9;
}
.footerCopyright {
	width: 1000px;
	margin: 40px auto;
}
.footerCopyright p {
	font: 13px/30px "微软雅黑";
    text-align: center;
    color: #b1b3b9;
}
.footerCopyright a {
	color: #999;
}
.footerCopyright a:hover {
	color: #999;
}
.copyrightIcon {
	display: inline-block;
	width: 16px;
	height: 16px;
	margin-left: 5px;
	margin-top: -2px;
	vertical-align: middle;
	background: url(../img/bg.png) no-repeat 0 bottom;
}
.copyrightIcon2 {
	width: 20px;
	height: 20px;
	margin-top: -12px;
	background: url(../img/bg.png) no-repeat right bottom;
}

/* 首页 */

#poster {
	width: 100%;
	height: 445px;
	position: relative;
	overflow: hidden;
}
.posterC {
	display: inline-block;
	width: 100%;
	height: 500px;
	background: url(../img/20160713154957678313.jpg) no-repeat center center;
}
.posterL {
	position: absolute;
	left: 0;
	top: 50%;
	margin-top: -28px;
	width: 60px;
	height: 58px;
	background: url(../img/bg.png) no-repeat 14px -304px;
}
.posterL:hover {
	margin-top: -60px;
	height: 160px;
	background: url(../img/bg.png) no-repeat 0 -452px;
}
.posterR {
	position: absolute;
	right: 0;
	top: 50%;
	margin-top: -28px;
	width: 60px;
	height: 58px;
	background: url(../img/bg.png) no-repeat -204px -302px;
}
.posterR:hover {
	margin-top: -60px;
	height: 160px;
	background: url(../img/bg.png) no-repeat -190px -452px;
}
.posterB {
	width: 100%;
	height: 10px;
	position: absolute;
	bottom: 80px;
}
.posterBCon {
	height: 10px;
	text-align: center;
	line-height: 0;
}
.posterBCon a {
	display: inline-block;
	margin: 0 10px;
	width: 6px;
	height: 6px;
	background: url(../img/bg.png) no-repeat -142px 0;
	vertical-align: middle;
}
.posterBCon a:hover,
.posterBCon .posterBActive {
	margin: 0 8px;
	width: 10px;
	height: 10px;
	background: url(../img/bg.png) no-repeat -206px 0;
}
.downLoad {
	width: 100%;
	height: 60px;
	position: absolute;
	bottom: 0;
}
.downLoadBg {
	width: 100%;
	height: 60px;
	position: absolute;
	bottom: 0;
	background: #000;
	opacity: .3;
	filter: alpha(opacity = 30);
}
.downLoadCon {
	position: absolute;
	top: 0;
	left: 50%;
	margin-left: -325px;
	height: 60px;
}
.downLoadCon a {
	float: left;
	width: 130px;
	padding: 0 45px 0 30px;
	font: 15px "微软雅黑";
	line-height: 25px;
	margin: 20px 0 0 55px;
	color: #fff;
	text-align: center;
	background: url(../img/bg.png) no-repeat;
}
.downLoadCon a:hover {
	color: #ffffdf;
}
.downLoadCon .downPC {
	margin-left: 0;
	background-position: -226px -122px;
}
.downPC:hover {
	background-position: -226px -178px;
}
.downLoadCon .downiPhone {
	background-position: -48px -36px;
}
.downiPhone:hover {
	background-position: -258px -36px;
}
.downLoadCon .downAndroid {
	background-position: -48px -78px;
}
.downAndroid:hover {
	background-position: -258px -78px;
}
.downLoadLine {
	float: left;
	margin-top: 25px;
	height: 18px;
	border-right: 1px solid #fff;
	opacity: .3;
	filter: alpha(opacity = 20);
}
.musicList {
	margin-top: 40px;
	width: 100%;
}
.musicListCon {
	width: 1000px;
	height: 385px;
	margin: 0 auto;
}
.musicListHot {
	float: left;
	width: 650px;
}
.listHotNav {
	height: 60px;
}
.listHotNav h3 {
	float: left;
	padding-top: 30px;
	height: 0;
	width: 120px;
	overflow: hidden;
	background: url(../img/selectlist.jpg) no-repeat;
}
.listHotNav span {
	float: right;
	font: 13px/33px "微软雅黑";
}
.listHotNav a {
	color: #999;
}
.listHotCon {
	height: 325px;
}
.mostHot {
	float: left;
	width: 325px;
	position: relative;
}
.mostHot img {
	position: relative;
	width: 325px;
	height: 325px;
}
.hotNum {
	position: absolute;
	top: 0;
	right: 0;
	width: 160px;
	height: 30px;
	background: url(../img/bg.png) no-repeat right -624px;
}
.hotNumIcon {
	float: right;
	margin: 8px 10px 0 0;
	width: 14px;
	height: 13px;
	background: url(../img/bg.png) no-repeat 0 -624px;
}
.hotNumListen {
	float: right;
	margin-right: 8px;
	font: 13px/29px "微软雅黑";
	color: #fff;
	text-align: right;
}
.hotMessage {
	position: absolute;
	bottom: 0;
	height: 50px;
	width: 100%;
	background: #000;
	opacity: .5;
	filter: alpha(opacity = 50);
	font: 14px/19px "微软雅黑";
	color: #fff;
	text-indent: 7px;
}
.hotTip {
	margin-top: 6px;
}
.hotTit {
	color: #cfcfcf;
}
.hotHover {
	position: absolute;
	top: 0;
	left: 0;
	height: 100%;
	width: 100%;
	background: #000;
	opacity: .3;
	filter: alpha(opacity = 30);
	display: none;
}
.hotPlayHover{
	position: absolute;
	bottom: 7px;
	right: 7px;
	width: 36px;
	height: 36px;
	background: url(../img/bg.png) no-repeat 0 -680px;
	display: none;
}
.hotList li:hover .hotHover,
.hotList li:hover .hotPlayHover,
.mostHot:hover .hotPlayHover,
.mostHot:hover .hotHover {
	display: inline-block;
}
.hotPlayHover:hover {
	background: url(../img/bg.png) no-repeat -86px -680px;
}
.hotList {
	float: left;
	width: 325px;
	height: 325px;
	overflow: hidden;
}
.hotList li {
	float: left;
	margin-left: 5px;
	margin-bottom: 5px;
	width: 160px;
	height: 160px;
	position: relative;
}
.hotList img {
	width: 160px;
	height: 160px;
}
.hotList .hotListW {
	margin-right: -5px;
}
.hotList .hotMessage p {
	overflow: hidden;
	text-overflow: ellipsis;
	width: 107px;
	white-space: nowrap;
}
.hotList .hotPlayHover {
	right: 12px;
}
.musicListRank {
	float: right;
	margin-left: 30px;
	width: 320px;
}
.listHotNav .hotRank {
	background: url(../img/hotlist.jpg) no-repeat;
}
.rankCon {
	margin-bottom: -15px;
}
.rankCon li {
	margin-bottom: 15px;
	background-color: #f6f6f6;
	height: 98px;
	position: relative;
}
.rankListImg {
	float: left;
	position: relative;
}
.rankCon img {
	width: 98px;
	height: 98px;
}
.rankList {
	float: right;
	width: 202px;
	padding: 15px 10px;	
	height: 68px;
}
.rankList dt {
	font: bold 14px/24px "微软雅黑";
	color: #333;
}
.rankList dd {
	width: 180px;
	font: 14px/24px "微软雅黑";
    color: #555;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.rankConIcon {
	position: absolute;
	right: 10px;
	top: 50%;
	margin-top: -7px;
	width: 7px;
	height: 13px;
	background: url(../img/bg.png) no-repeat 0 -744px;
}
.rankListBg {
	position: absolute;
	top: 0;
	left: 0;
	width: 100%;
	height: 100%;
	background-color: #000;
	opacity: .3;
	filter: alpha(opacity = 30);
	display: none;
}
.rankListPlay {
	position: absolute;
	top: 50%;
	left: 50%;
	margin-top: -18px;
	margin-left: -18px;
	width: 36px;
	height: 36px;
	background: url(../img/bg.png) no-repeat 0 -680px;
	display: none;
}
.rankCon li:hover .rankListPlay,
.rankCon li:hover .rankListBg {
	display: inline-block;
}
.rankListPlay:hover {
	background: url(../img/bg.png) no-repeat -86px -680px;
}
.ad {
	margin-top: 15px;
}
.adCon {
	width: 1000px;
	height: 80px;
	margin: 0 auto;
}
#newMusicMV {
	margin-top: 40px;
}
.newMusicMVCon {
	width: 1000px;
	height: 375px;
	margin: 0 auto;
}
.newMusicMVCon .listHotNav {
	height: 50px;
}
.newMusicList {
	float: left;
	width: 650px;
}
.listHotNav .newMusic {
	background: url(../img/newlist.jpg) no-repeat;
}
.newMusicNav {
	float: left;
	margin-left: 30px;
	font: 14px/30px "微软雅黑";
}
.newMusicNav a {
	display: inline-block;
	margin-right: 24px;
	color: #000;
}
.playAll {
	position: relative;
	float: right;
	font: 13px/29px "微软雅黑";
	color: #555;
	border: 1px solid #dbdbdb;
    border-radius: 2px;
    padding: 0 10px 0 26px;
}
.playAll span {
	position: absolute;
	top: 8px;
	left: 10px;
	width: 12px;
	height: 14px;
	background: url(../img/bg.png) no-repeat -70px -744px;
}
.playAll:hover {
	border-color: #009af3;
}
.playAll:hover span {
	background-position: -178px -744px;
}
.newMusicCon {
	padding-top: 10px;
	font: 13px/35px "微软雅黑";
	border-top: 1px solid #f0f0f0;
}
.newMusicCon li {
	position: relative;
	height: 35px;
}
.newMusicCon a {
	position: relative;
	display: inline-block;
	padding: 0 10px;
	height: 35px;
	width: 630px;
	color: #333;
}
.newMusicTit {
	float: left;
}
.newMusicTime {
	float: right;
}
.newMusicCon li:hover a {
	background-color: #f5f8fb;
	color: #009af3;
}
.newMusicPlay {
	position: absolute;
	top: 10px;
	right: 80px;
	width: 12px;
	height: 14px;
	background: url(../img/bg.png) no-repeat 0 -784px;
	display: none;
}
.newMusicCon .newMusicDown {
	position: absolute;
	top: 10px;
	right: 57px;
	width: 13px;
	height: 13px;
	padding: 0;
	background: url(../img/bg.png) no-repeat -54px -784px;
	display: none;
}
.newMusicCon li:hover .newMusicDown,
.newMusicCon li:hover .newMusicPlay {
	display: inline-block;
}
.newMusicDown:hover {
	background-position: -86px -784px;
}
.newMusicPlay:hover {
	background-position: -28px -784px;
}
.exclusive {
	float: left;
	width: 21px;
	height: 12px;
	margin: 12px 0 0 10px;
	background: url(../img/bg.png) no-repeat -126px -784px;
}
.switch {
	position: relative;
	height: 12px;
	font: 12px/12px "微软雅黑";
	margin-top: 13px;
}
.switchlast {
	position: absolute;
	top: 1px;
	left: 290px;
	width: 6px;
	height: 9px;
	background: url(../img/bg.png) no-repeat -170px -784px;
}
.switchnext {
	position: absolute;
	top: 1px;
	right: 300px;
	width: 6px;
	height: 9px;
	background: url(../img/bg.png) no-repeat -242px -784px;
}
.switchlast:hover {
	background-position: -220px -784px;
}
.switchNum {
	position: absolute;
	top: 0;
	left: 310px;
	color: #8d8d8d;
}
.newMVList {
	float: right;
	width: 320px;
}
.listHotNav .newMV {
	background: url(../img/albumlist.jpg) no-repeat;
}
.MVConHot{
	position: relative;
	height: 175px;
	width: 100%;
	margin-bottom: 12px;
}
.MVConHot img {
	height: 175px;
	width: 320px;
}
.MVConHotMessage {
	position: absolute;
	bottom: 0;
	width: 100%;
	height: 38px;
	background: #000;
	opacity: .5;
	filter: alpha(opacity = 50);
	padding: 6px 0;
	text-indent: 8px;
	font: 14px/19px "微软雅黑";
	color: #fff;
}
.MVConHotAuthor {
	color: #cfcfcf;
}
.MVConHotLink {
	position: absolute;
	top: 0;
	left: 0;
	width: 320px;
	height: 175px;
	background: #000;
	opacity: .3;
	filter: alpha(opacity = 30);
	display: none;
}
.MVConHotIcon {
	position: absolute;
	top: 50%;
	left: 50%;
	margin: -24px 0 0 -24px;
	width: 48px;
	height: 48px;
	background: url(../img/bg.png) no-repeat 0 -830px;
}
.MVConHot:hover .MVConHotLink {
	display: inline-block;
}
.MVConHotIcon:hover {
	background-position: -82px -830px;
}
.MVConList a {
	float: left;
	position: relative;
	width: 154px;
	margin-right: 12px;
}
.MVConList img {
	height: 84px;
	width: 154px;
}
.MVListMessage {
	padding-top: 5px;
	font: 14px/19px "微软雅黑";
	color: #444;
}
.MVListMessageAuthor {
	font-size: 12px;
	color: #888;
}
.MVConListLink {
	position: absolute;
	top: 0;
	left: 0;
	width: 154px;
	height: 84px;
	background: #000;
	opacity: .3;
	filter: alpha(opacity = 30);
	display: none;
}
.MVConListIcon {
	position: absolute;
	top: 50%;
	left: 50%;
	margin: -24px 0 0 -24px;
	width: 48px;
	height: 48px;
	background: url(../img/bg.png) no-repeat 0 -830px;
	display: none;
}
.MVConList a:hover .MVConListIcon,
.MVConList a:hover .MVConListLink {
	display: inline-block;
}
.MVConList a:hover .MVListMessageTit {
	color: #009af3;
}
.MVConListIcon:hover {
	background-position: -82px -830px;
}
.MVConList .MVListOne {
	margin-right: 0;
}
.ad2 {
	margin-top: 40px;
}
.ad2 .adCon {
	height: 100px;
}
.hotRadioMusicer {
	margin-top: 40px;
}
.hotRadioMusicerCon {
	margin: 0 auto;
	width: 1000px;
}
.hotMusicerNavList {
	float: left;
	margin-left: 17px;
	font: 14px/30px "微软雅黑";
}
.hotMusicerNavList a {
	float: left;
	margin-right: 20px;
	color: #000;
}
.listHotNav .hotMusicerMore {
	line-height: 30px;
}
.listHotNav .hotRadioNav {
	background: url(../img/hotredio.jpg) no-repeat;
}
.listHotNav .hotMusicerNav {
