}
.MvListLi li {
	float: left;
	margin: 0 20px 10px 0;
}
.MvListLi ul a {
	display: block;
	position: relative;
}
.MvListLi img {
	width: 140px;
	height: 78px;
}
.MvListLiPlay {
	position: absolute;
	right: 13px;
	bottom: 12px;
	width: 21px;
	height: 21px;
	background: url(../img/bgOther.png) no-repeat 0 -858px;
}
.MvListLiB {
	position: absolute;
	right: 0;
	bottom: 0;
	width: 140px;
	height: 33px;
	background: url(../img/bgOther.png) no-repeat right -664px;
}
.MvListLiTitle {
	display: block;
	margin: 5px 0 0 3px;
	width: 124px;
	font: 14px/21px "微软雅黑";
	color: #555;
	white-space: nowrap;
	overflow: hidden;
	text-overflow: ellipsis;
}
.MvListLiNav {
	margin-top: 15px;
	margin-bottom: 2px;
	text-align: center;
	font: italic 14px/21px Arial;
}
.MvListLiNav a {
	margin: 0 8px;
	color: #333;
}
.MvListLiNav .MvListLiNavAct,
.MvListLiNav a:hover {
	font-weight: bold;
	text-decoration: underline;
	color: #333;
}
.MvListLiNavNext {
	font: normal 12px/18px Arial;
}

a {
	text-decoration: none;
}
ul {
	margin: 0;
	padding: 0;
	list-style: none;
}
h2 {
	font-weight: normal;
	margin: 0;
}
#nav {
	height: 55px;
	background-color: #2c323b;
}
.navContent {
	width: 1000px;
	margin: 0 auto;
}
.navContentL {
	float: left;
	font: 16px/55px "微软雅黑";
}
.navMore,
.navContentL a {
	float: left;
	padding: 0 30px;
	color: #ddd;
}
.navMore:hover h2 a,
.navContentL .navActive,
.navContentL a:hover {
	color: #fff;
	background-color: #0c8ed9;
}
.navMore {
	width: 113px;
	padding: 0;
	position: relative;
	background: url(../img/bg.png) no-repeat 77px -16px;
}
.navMore:hover {
	background: #0c8ed9 url(../img/bg.png) no-repeat 77px -53px;
}
.navMore h2 {
	padding: 0 30px;
	margin-left: 5px;
	font: 16px/55px "微软雅黑";
}
.navMore a {
	color: #ddd;
}
.hiddenNav {
	position: absolute;
	top: 55px;
	left: 0;
	height: 0;
	overflow: hidden;
	width: 100%;
	background-color: #252b34; 
}
.navMore:hover .hiddenNav {
	height: 146px;
}
.hiddenNav li {
	width: 100%;
	height: 36px;
	font: 15px/36px "微软雅黑";
	text-align: center;
}
.hiddenNav a {
	display: block;
	color: #bbb;
}
.hiddenNav a:hover {
	color: #fff;
	background-color: #2d343d;
	line-height: 34px;
	border-top: 1px solid #383d44;
}
.navContentR {
	float: right;
	font: 13px/1 "微软雅黑";
	margin-top: 21px;
}
.navContentR a {
	display: inline-block;
	margin-left: 30px;
	padding-left: 20px;
	color: #bbb;
	background-image: url(../img/bg.png);
	background-repeat: no-repeat;
}
.navContentR a:hover {
	color: #14a9ff;
}
.show {
	background-position: 0 -111px;
}
.live {
	background-position: 0 -143px;
}
.musicAuthor {
	background-position: 0 -174px;
}
.game {
	background-position: 0 -204px;
}
.shop {
	background-position: 0 -230px;
}
.show:hover {
	background-position: -95px -111px;
}
.live:hover {
	background-position: -95px -143px;
}
.musicAuthor:hover {
	background-position: -95px -174px;
}
.game:hover {
	background-position: -95px -204px;
}
.shop:hover {
	background-position: -95px -230px;
}

